final class CrossLanguageMediaTests: XCTestCase {

    private func data(_ bytes: [UInt8]) -> Data { Data(bytes) }

    private func sha256(_ d: Data) -> String {
        let hash = SHA256.hash(data: d)
        return hash.map { String(format: "%02x", $0) }.joined()
    }

    func testDecodeUserText() throws {
        let env = try Wire.decode(data(Fixtures.textUserHello))
        XCTAssertEqual(env.kind, .user)
        XCTAssertEqual(env.id, "abc")
        XCTAssertEqual(env.text, "hello")
        XCTAssertEqual(env.ts, 1_700_000_000_000)
    }

    func testDecodeAck() throws {
        let env = try Wire.decode(data(Fixtures.ackBasic))
        XCTAssertEqual(env.kind, .ack)
        XCTAssertEqual(env.id, "ack-1")
    }

    func testDecodeError() throws {
        let env = try Wire.decode(data(Fixtures.errorMediaTooLarge))
        XCTAssertEqual(env.kind, .error)
        XCTAssertEqual(env.code, "MEDIA_TOO_LARGE")
        XCTAssertEqual(env.text, "attachment exceeded 25 MiB")
    }

    func testReassemble8kImage() throws {
        let r = Wire.MediaReassembler()
        var assembled: Wire.ReassembledMedia? = nil
        for chunk in Fixtures.imageImage8kChunks {
            let env = try Wire.decode(data(chunk))
            XCTAssertEqual(env.kind, .media)
            if let out = r.push(env) {
                assembled = out
            }
        }
        XCTAssertNotNil(assembled)
        XCTAssertEqual(assembled?.media, .image)
        XCTAssertEqual(assembled?.from, .agent)
        XCTAssertEqual(assembled?.filename, "shot.png")
        XCTAssertEqual(assembled?.mime, "image/png")
        XCTAssertEqual(assembled?.caption, "here is your shot")
        XCTAssertEqual(assembled?.bytes.count, 8192)
        XCTAssertEqual(sha256(assembled!.bytes), Fixtures.imageImage8kSha256)
    }

    func testReassemble8kImageOutOfOrder() throws {
        let r = Wire.MediaReassembler()
        var assembled: Wire.ReassembledMedia? = nil
        // Push chunks in reverse order.
        for chunk in Fixtures.imageImage8kChunks.reversed() {
            let env = try Wire.decode(data(chunk))
            if let out = r.push(env) { assembled = out }
        }
        XCTAssertNotNil(assembled)
        XCTAssertEqual(assembled?.bytes.count, 8192)
        XCTAssertEqual(sha256(assembled!.bytes), Fixtures.imageImage8kSha256)
    }

    func testReassemble4kFile() throws {
        let r = Wire.MediaReassembler()
        var assembled: Wire.ReassembledMedia? = nil
        for chunk in Fixtures.fileFile4kChunks {
            let env = try Wire.decode(data(chunk))
            if let out = r.push(env) { assembled = out }
        }
        XCTAssertNotNil(assembled)
        XCTAssertEqual(assembled?.media, .file)
        XCTAssertEqual(assembled?.from, .user)
        XCTAssertEqual(assembled?.filename, "data.bin")
        XCTAssertEqual(assembled?.bytes.count, 4096)
        XCTAssertEqual(sha256(assembled!.bytes), Fixtures.fileFile4kSha256)
    }

    func testFixtureChunksRespectMaxBytes() {
        for chunk in Fixtures.imageImage8kChunks {
            XCTAssertLessThanOrEqual(chunk.count, Wire.maxEnvelopeBytes,
                "TS-encoded chunk exceeded maxEnvelopeBytes (drift)")
        }
        for chunk in Fixtures.fileFile4kChunks {
            XCTAssertLessThanOrEqual(chunk.count, Wire.maxEnvelopeBytes)
        }
    }
}
